"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const stops=[['Brief','Set the route context.'],['Review','Check the decision.'],['Release','Share the approved route.']];
export default function WaypointRailNavigator(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <nav aria-label="Route waypoints" className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">route waypoints</p><div className="relative mt-4 grid gap-2 border-l-2 border-[#ececee] pl-5"><motion.i aria-hidden animate={{y:active*52}} transition={reduced?{duration:.12}:{type:"spring",stiffness:340,damping:27}} className="absolute -left-[7px] top-4 h-3 w-3 rounded-full bg-[#f97316]"/>{stops.map((stop,i)=><motion.button key={stop[0]} type="button" aria-current={active===i?"page":undefined} onClick={()=>setActive(i)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="min-h-11 rounded-xl px-3 text-left outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"><span className="block text-sm font-extrabold text-[#111]">{stop[0]}</span><span className="text-xs text-[#4a4a4f]">{active===i?stop[1]:"Select waypoint"}</span></motion.button>)}</div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Current waypoint: {stops[active][0]}.</p></nav>}
